   266	func getUint64HeaderValue(record *kgo.Record, headerKey string) (uint64, error) {
   267		if headerKey == "" {
   268			return 0, nil
   269		}
   270		headerValue := getHeaderValue(record, headerKey)
   271		if headerValue == "" {
   272			return 0, nil
   273		}
   274		value, err := strconv.ParseUint(headerValue, 10, 64)
   275		if err != nil {
   276			return 0, fmt.Errorf("error parsing header %s value %s: %w", headerKey, headerValue, err)
   277		}
