   281	func getBoolHeaderValue(record *kgo.Record, headerKey string) (bool, error) {
   282		if headerKey == "" {
   283			return false, nil
   284		}
   285		headerValue := getHeaderValue(record, headerKey)
   286		if headerValue == "" {
   287			return false, nil
   288		}
   289		value, err := strconv.ParseBool(headerValue)
   290		if err != nil {
