   296	func getHeaderValue(record *kgo.Record, headerKey string) string {
   297		if headerKey == "" {
   298			return ""
   299		}
   300		for _, header := range record.Headers {
   301			if header.Key == headerKey {
   302				return string(header.Value)
   303			}
   304		}
   305		return ""
   306	}
   307	
   308	func publicationTagsFromKafkaRecord(record *kgo.Record, tagsHeaderPrefix string) map[string]string {
   309		if tagsHeaderPrefix == "" {
   310			return nil
   311		}
   312		var tags map[string]string
   313		for _, header := range record.Headers {
   314			if strings.HasPrefix(header.Key, tagsHeaderPrefix) {
   315				if tags == nil {
   316					tags = make(map[string]string)
   317				}
   318				tags[header.Key[len(tagsHeaderPrefix):]] = string(header.Value)
   319			}
   320		}
   321		return tags
   322	}
