   324	func (pc *partitionConsumer) processPublicationDataRecord(ctx context.Context, record *kgo.Record) error {
   325		data := record.Value
   326		idempotencyKey := getHeaderValue(record, pc.config.PublicationDataMode.IdempotencyKeyHeader)
   327		delta, err := getBoolHeaderValue(record, pc.config.PublicationDataMode.DeltaHeader)
   328		if err != nil {
   329			pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Msg("error parsing delta header value, skip message")
   330			return nil
   331		}
   332		channelsHeader := getHeaderValue(record, pc.config.PublicationDataMode.ChannelsHeader)
   333		if channelsHeader == "" {
   334			pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("no channels found, skip message")
   335			return nil
   336		}
   337		channels := strings.Split(channelsHeader, ",")
   338		if len(channels) == 0 || (len(channels) == 1 && channels[0] == "") {
   339			pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("no channels found, skip message")
   340			return nil
   341		}
   342		version, err := getUint64HeaderValue(record, pc.config.PublicationDataMode.VersionHeader)
   343		if err != nil {
   344			pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Msg("error parsing version header value, skip message")
   345			return nil
   346		}
   347		return pc.dispatcher.DispatchPublication(
   348			ctx,
   349			channels,
   350			api.ConsumedPublication{
   351				Data:           data,
   352				IdempotencyKey: idempotencyKey,
   353				Delta:          delta,
   354				Tags:           publicationTagsFromKafkaRecord(record, pc.config.PublicationDataMode.TagsHeaderPrefix),
   355				Version:        version,
   356				VersionEpoch:   getHeaderValue(record, pc.config.PublicationDataMode.VersionEpochHeader),
   357			},
   358		)
   359	}
