   361	func (pc *partitionConsumer) processRecord(ctx context.Context, record *kgo.Record) error {
   362		if pc.config.PublicationDataMode.Enabled {
   363			return pc.processPublicationDataRecord(ctx, record)
   364		}
   365		method := getHeaderValue(record, pc.config.MethodHeader)
   366		return pc.dispatcher.DispatchCommand(ctx, method, record.Value)
   367	}
   368	
   369	func (pc *partitionConsumer) processRecords(records []*kgo.Record) {
   370		for _, record := range records {
   371			select {
   372			case <-pc.partitionCtx.Done():
   373				return
   374			default:
   375			}
   376	
   377			var backoffDuration time.Duration = 0
   378			retries := 0
   379			for {
   380				err := pc.processRecord(pc.partitionCtx, record)
   381				if err == nil {
   382					if retries > 0 {
   383						pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("OK processing message after errors")
   384					}
   385					if logging.Enabled(logging.TraceLevel) {
   386						pc.common.log.Trace().Str("topic", record.Topic).Int32("partition", record.Partition).Int64("offset", record.Offset).Msg("record processed")
   387					}
   388					metrics.ConsumerProcessedTotal.WithLabelValues(pc.name).Inc()
   389					pc.cl.MarkCommitRecords(record)
   390					break
   391				}
   392				if errors.Is(err, context.Canceled) {
   393					return
   394				}
   395				retries++
   396				backoffDuration = getNextBackoffDuration(backoffDuration, retries)
   397				metrics.ConsumerErrorsTotal.WithLabelValues(pc.name).Inc()
   398				pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Str("next_attempt_in", backoffDuration.String()).Msg("error processing consumed record")
   399				select {
   400				case <-time.After(backoffDuration):
   401				case <-pc.partitionCtx.Done():
   402					return
   403				}
   404			}
   405		}
   406	}
   407	
   408	func (pc *partitionConsumer) consume() {
   409		if logging.Enabled(logging.DebugLevel) {
   410			pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("starting partition consumer")
   411		}
   412		defer close(pc.done)
   413		defer pc.queue.Close()
   414		defer func() {
   415			if logging.Enabled(logging.DebugLevel) {
   416				// Queue is closed, partition consumer is shutting down.
   417				pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("partition consumer shutting down")
   418			}
   419		}()
   420	
   421		partitionsToResume := map[string][]int32{pc.topic: {pc.partition}}
   422		resumeConsuming := func() {
   423			pc.cl.ResumeFetchPartitions(partitionsToResume)
   424		}
   425		defer resumeConsuming()
   426	
   427		for {
   428			select {
   429			case <-pc.partitionCtx.Done():
   430				return
   431			case <-pc.queue.NotEmpty():
   432				if pc.queue.IsClosed() {
   433					return
   434				}
   435				// Process all available items in the queue.
   436				for {
   437					select {
   438					case <-pc.partitionCtx.Done():
   439						return
   440					default:
   441					}
   442					p, ok := pc.queue.Pop()
   443					if !ok {
   444						break
   445					}
   446					pc.processRecords(p.Records)
   447					// Resume partition after processing this batch. Only one additional batch will
   448					// be added to the queue before we pause again.
   449					resumeConsuming()
   450				}
   451			}
   452		}
   453	}
