   455	// unboundedQueue implements an unbounded queue for FetchTopicPartition
   456	type unboundedQueue struct {
   457		mu         sync.RWMutex
   458		items      []kgo.FetchTopicPartition
   459		numRecords int
   460		notEmpty   chan struct{}
   461		closed     bool
   462	}
   463	
   464	func newUnboundedQueue() *unboundedQueue {
   465		return &unboundedQueue{
   466			items:    make([]kgo.FetchTopicPartition, 0),
   467			notEmpty: make(chan struct{}, 1),
   468		}
   469	}
   470	
   471	func (q *unboundedQueue) Push(item kgo.FetchTopicPartition) bool {
   472		q.mu.Lock()
   473		defer q.mu.Unlock()
   474	
   475		if q.closed {
   476			return false
   477		}
   478	
   479		q.items = append(q.items, item)
   480		q.numRecords += len(item.Records)
   481	
   482		// Signal that queue is not empty.
   483		select {
   484		case q.notEmpty <- struct{}{}:
   485		default:
   486		}
   487	
   488		return true
   489	}
   490	
   491	func (q *unboundedQueue) Pop() (kgo.FetchTopicPartition, bool) {
   492		q.mu.Lock()
   493		defer q.mu.Unlock()
   494	
   495		if q.closed || len(q.items) == 0 {
   496			return kgo.FetchTopicPartition{}, false
   497		}
   498	
   499		// We do not expect many items in the queue, so we can use a simple slice pop operation and
   500		// not worry about memory being reserved for the underlying slice.
   501		item := q.items[0]
   502		q.items[0] = kgo.FetchTopicPartition{} // Clear the first item for faster GC.
   503		q.items = q.items[1:]
   504		q.numRecords -= len(item.Records)
   505	
   506		return item, true
   507	}
   508	
   509	func (q *unboundedQueue) NumRecords() int {
   510		q.mu.RLock()
   511		defer q.mu.RUnlock()
   512		return q.numRecords
   513	}
   514	
   515	func (q *unboundedQueue) Close() {
   516		q.mu.Lock()
   517		defer q.mu.Unlock()
   518	
   519		if !q.closed {
   520			q.closed = true
   521			close(q.notEmpty)
   522		}
   523	}
   524	
   525	func (q *unboundedQueue) IsClosed() bool {
   526		q.mu.RLock()
   527		defer q.mu.RUnlock()
   528		return q.closed
   529	}
   530	
   531	func (q *unboundedQueue) NotEmpty() <-chan struct{} {
   532		return q.notEmpty
   533	}
